-- et survivent à leur régénération.
local G = AscensionFR.DB.Gossip
local T = AscensionFR.DB.TextesPNJ
local Q = AscensionFR.DB.Quetes
local function quete(id, champ, texte)
    local e = Q[id]
    if e then e[champ] = texte else Q[id] = { [champ] = texte } end
end

