G["|cff000000Catch of the Day: Trout|r"]="|cff000000Prise du jour : Truite|r"
G["|cff000000From Grain to Flour|r"]="|cff000000Du grain à la farine|r"
G["|cff000000From Plot to Plate|r"]="|cff000000De l'intrigue au plaques|r"
G["|cff000000Gentle Herd|r"]="|cff000000Troupeau doux|r"
G["|cff000000Graysky's Cheese Platter|r"]="|cff000000Plateau de fromages de Graysky|r"
